                gvrs := info.EquivalentResourceMapper.EquivalentResourcesFor(gr.WithVersion(""), "")
                for _, gvr := range gvrs {
                        seen[gvr.GroupResource()] = struct{}{}
                }
                ret = append(ret, info)
        }
        return ret
}

